// ── Advanced Search: Sanitize & Normalize ──────────────────────────────
const query = $json.query || {};

const MAX_Q_LENGTH = 150;
const MAX_LIMIT    = 100;
const MAX_OFFSET   = 10000;

// ── q ───────────────────────────────────────────────────────────────────
const raw_q = String(query.q || '').trim().toLowerCase();
let q_norm  = null;
let q_error = null;

if (raw_q.length === 0) {
  q_error = 'missing';
} else if (raw_q.length < 2) {
  q_error = 'too_short';
} else if (raw_q.length > MAX_Q_LENGTH) {
  q_error = 'too_long';
} else {
  q_norm = raw_q;
}

// ── category ────────────────────────────────────────────────────────────
// Accept any entity_type slug (letters, digits, underscores only — safe for parameterized query)
const raw_cat = String(query.category || '').trim().toLowerCase();
let category_norm  = '*';
let category_error = '';

if (raw_cat.length > 0) {
  if (/^[a-z0-9_]+$/.test(raw_cat)) {
    category_norm = raw_cat;
  } else {
    category_error = raw_cat;
  }
}

// ── limit / offset ──────────────────────────────────────────────────────
const limit_norm  = Math.min(Math.max(parseInt(query.limit)  || 25, 1), MAX_LIMIT);
const offset_norm = Math.min(Math.max(parseInt(query.offset) || 0,  0), MAX_OFFSET);

return {
  json: {
    q_norm,
    q_error,
    category_norm,
    category_error,
    limit_norm,
    offset_norm
  }
};

